// 記事一括生成スクリプト (最大20件)
const { createClient } = require('@libsql/client');
const Anthropic = require('@anthropic-ai/sdk').default;
require('dotenv').config({ path: '.env.local' });
require('dotenv').config({ path: '.env' });

const client = createClient({
  url: process.env.TURSO_DATABASE_URL,
  authToken: process.env.TURSO_AUTH_TOKEN,
});
const ANTHROPIC_KEY = process.env.ANTHROPIC_API_KEY || '';
const ai = new Anthropic({ apiKey: ANTHROPIC_KEY });

const CATEGORY_IDS = {
  "ChatGPT活用術": "cmrg33bif0001o3h1ok0jshe7",
  "AI業務効率化": "cmrg33big0002o3h1wgu0w6t0",
  "AIツール比較": "cmrg33big0003o3h1kvoj5tvo",
  "プロンプト技術": "cmrg33bih0004o3h1uojawgzu",
  "プロンプトエンジニアリング": "cmrg33bih0004o3h1uojawgzu",
  "AI副業・収益化": "cmrg33bii0005o3h1do852gfy",
  "AI最新ニュース": "cmrg33bii0006o3h1ntmi7odd",
};

function slugify(text) {
  return text.toLowerCase().replace(/[^\w\s-]/g, '').replace(/[\s]+/g, '-').replace(/-+/g, '-').slice(0, 60).replace(/^-|-$/g, '');
}

async function generateArticle(keyword) {
  const response = await ai.messages.create({
    model: 'claude-sonnet-4-6',
    max_tokens: 8192,
    messages: [{
      role: 'user',
      content: `あなたはAI活用・業務効率化専門のトップSEOライターです。
以下のキーワードで、Google検索1位・AIオーバービュー（AIO）掲載・月間5万PV以上を目指す超高品質な記事を執筆してください。

キーワード: ${keyword}

【必須構成】
1. ## この記事でわかること（箇条書き3〜5項目）
2. ## ${keyword}とは（基本解説・定義）
3. ## 具体的な使い方・手順（番号付きリスト）
4. ## 実践的な活用事例・おすすめポイント
5. ## よくある質問（FAQ）
   ### [質問1]？
   [回答100〜200文字]
   ### [質問2]？
   [回答100〜200文字]
   ### [質問3]？
   [回答100〜200文字]
6. ## まとめ（要点箇条書き＋次のアクション）

【要件】
- 文字数: 3000〜4000文字
- キーワードをタイトル・H2・リード文・まとめに必ず含める
- 具体的な数字・事例・手順を入れる
- FAQ必須（Googleがスニペット・AIOで引用しやすい形式）
- 読者: AIに興味があるビジネスパーソン・副業希望者

以下のJSON形式のみで回答してください（JSON以外のテキストは含めないこと）:
{"title":"記事タイトル（60文字以内・数字含む）","excerpt":"要約（120文字以内・検索意図に直接回答）","content":"本文（Markdown・3000〜4000文字・上記構成厳守）","seoTitle":"SEOタイトル（60文字以内）","seoDescription":"メタディスクリプション（120文字以内・CTAあり）","seoKeywords":"${keyword},AI活用,ChatGPT,業務効率化"}`
    }],
  });
  const text = response.content[0].type === 'text' ? response.content[0].text : '';
  const match = text.match(/\{[\s\S]*\}/);
  if (!match) throw new Error('JSON not found');
  return JSON.parse(match[0]);
}

async function main() {
  // ペンディングキーワードを取得
  const kwResult = await client.execute({
    sql: 'SELECT k.id, k.keyword, k.category FROM "Keyword" k WHERE k.status = ? ORDER BY k.searchVolume DESC LIMIT 20',
    args: ['pending']
  });
  const keywords = kwResult.rows;

  // 既存記事のキーワードを除外
  const artResult = await client.execute('SELECT seoKeywords FROM "Article" WHERE status = ?', ['published']);
  const usedKws = new Set(artResult.rows.flatMap(a => (a.seoKeywords || '').split(',').map(k => k.trim())));

  const pending = keywords.filter(k => !usedKws.has(k.keyword));
  console.log(`生成対象: ${pending.length} 件`);

  const generated = [];
  for (const kw of pending) {
    try {
      console.log(`生成中: ${kw.keyword}`);
      const result = await generateArticle(kw.keyword);
      const now = new Date().toISOString();
      const slug = slugify(result.title) + '-' + Date.now().toString(36);
      const id = 'bulk' + Date.now().toString(36) + Math.random().toString(36).slice(2, 6);
      const catId = (kw.category ? CATEGORY_IDS[kw.category] : null) || "cmrg33bif0001o3h1ok0jshe7";

      await client.execute({
        sql: `INSERT INTO "Article" (id, title, slug, excerpt, content, seoTitle, seoDescription, seoKeywords, wordCount, readingTime, aiGenerated, categoryId, status, publishedAt, createdAt, updatedAt) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
        args: [id, result.title, slug, result.excerpt, result.content, result.seoTitle, result.seoDescription, result.seoKeywords, result.content.length, Math.max(1, Math.floor(result.content.length / 400)), 1, catId, 'published', now, now, now]
      });
      generated.push(result.title);
      console.log(`✓ ${result.title}`);

      // レートリミット対策: 1秒待機
      await new Promise(r => setTimeout(r, 1000));
    } catch (e) {
      console.error(`✗ ${kw.keyword}: ${e.message}`);
    }
  }

  console.log(`\n完了: ${generated.length} 件生成`);
  generated.forEach(t => console.log(`  - ${t}`));
}

main().catch(console.error);
